const p = msg.payload;

const required = ['type', 'schema_version', 'timestamp', 'site_id', 'smart_energy', 'smart_city'];
const missing = required.filter(f => p[f] === undefined);

if (missing.length > 0) {
    msg.statusCode = 400;
    msg.payload = { error: 'Missing fields: ' + missing.join(', ') };
    return [null, msg];
}

if (p.type !== 'sim.tick') {
    msg.statusCode = 400;
    msg.payload = { error: 'Invalid type: ' + p.type + ', expected sim.tick' };
    return [null, msg];
}

flow.set('last_tick', p.timestamp);
flow.set('tick_count', (flow.get('tick_count') || 0) + 1);

return [msg, null];

const envelope = msg.payload;
const ts = envelope.timestamp;

const counts = {
    meters: (envelope.smart_energy.meters || []).length,
    pv: (envelope.smart_energy.pv || []).length,
    weather: envelope.smart_energy.weather ? 1 : 0,
    price: envelope.smart_energy.price ? 1 : 0,
    consumers: (envelope.smart_energy.consumers || []).length,
    lights: (envelope.smart_city.streetlights || []).length,
    traffic: (envelope.smart_city.traffic_readings || []).length,
    events: (envelope.smart_city.events || []).length,
    city_weather: envelope.smart_city.visibility ? 1 : 0
};

const total = Object.values(counts).reduce((a, b) => a + b, 0);

msg.payload = {
    status: 'accepted',
    timestamp: ts,
    messages_count: total,
    feeds: counts,
    tick_number: flow.get('tick_count') || 0
};
msg.statusCode = 200;

const debugMsg = {
    payload: {
        tick: flow.get('tick_count'),
        timestamp: ts,
        mode: envelope.mode,
        total_messages: total
    }
};

return [msg, debugMsg];
